import{_ as o,o as a,c as r,ag as p}from"./chunks/framework.WmBmIPw-.js";const k=JSON.parse('{"title":"2-opt、3-opt 与 k-opt（TSP/路径的边交换邻域）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/heuristics/simple/k-opt.md","filePath":"or-opt/heuristics/simple/k-opt.md","lastUpdated":1777190173000}'),e={name:"or-opt/heuristics/simple/k-opt.md"};function i(l,t,s,n,h,c){return a(),r("div",null,[...t[0]||(t[0]=[p('<h1 id="_2-opt、3-opt-与-k-opt-tsp-路径的边交换邻域" tabindex="-1">2-opt、3-opt 与 k-opt（TSP/路径的边交换邻域） <a class="header-anchor" href="#_2-opt、3-opt-与-k-opt-tsp-路径的边交换邻域" aria-label="Permalink to &quot;2-opt、3-opt 与 k-opt（TSP/路径的边交换邻域）&quot;">​</a></h1><p>2-opt 与 3-opt 是旅行商（TSP）及路径/路由问题中最常用的局部改进邻域：通过删去 2 条或 3 条边、再用唯一另一种方式重连，得到邻域中另一可行环路；k-opt 是同一思想的推广，一次用 k 条边断开后重连。属 <a href="./simple-heuristics.html">基础启发式</a> 中改进式，常嵌在 <a href="./hill-climbing.html">爬山</a>、VNS/ILS 的局搜子过程里。与跨邻域的 <a href="./../meta/vns.html">变邻域搜索</a> 可叠用：先 2-opt 抛光，再换结构或加 kick。</p><hr><h2 id="_2-opt-对称、无向-tsp-的经典叙述" tabindex="-1">2-opt（对称、无向 TSP 的经典叙述） <a class="header-anchor" href="#_2-opt-对称、无向-tsp-的经典叙述" aria-label="Permalink to &quot;2-opt（对称、无向 TSP 的经典叙述）&quot;">​</a></h2><ul><li><strong>作用对象</strong>：一哈密顿回路（点序的循环）。</li><li><strong>操作</strong>：选两条不共享端点的边 (a, b) 与 (c, d)，在环路上它们把环切成两段。删此二边、改接为 (a, c) 与 (b, d)（或等价另一对，依定向），得到同一顶点集上另一环。若距离对称，这相当于把一段路径在两条弧处「翻折」再接上。</li><li><strong>搜索</strong>：在全部 O(n²) 量级的 2-opt 对（或剪枝/候选边集）中找能缩短总长度的；可反复做直至无改进的 2-opt 改进（2-opt 最优），是典型的爬山邻域。</li><li><strong>复杂度感</strong>：单轮枚举约 O(n²)；达到 2-opt 最优所需轮数与实例有关；整体实用性强，实现相对简单。</li></ul><hr><h2 id="_3-opt" tabindex="-1">3-opt <a class="header-anchor" href="#_3-opt" aria-label="Permalink to &quot;3-opt&quot;">​</a></h2><ul><li><strong>操作</strong>：选三条两两端点均不同的边，删去后在剩余三段上有多种合法重连方式，从中选一种完成新环。</li><li><strong>与 2-opt 比较</strong>：邻域更「大」，单步能越过某些 2-opt 进不去的势垒；但候选数多，实现与调试更重。常采用「只在 2-opt 无改进时抽做 3-opt」等分层策略。</li></ul><hr><h2 id="k-opt-与-lin–kernighan-思想-简述" tabindex="-1">k-opt 与 Lin–Kernighan 思想（简述） <a class="header-anchor" href="#k-opt-与-lin–kernighan-思想-简述" aria-label="Permalink to &quot;k-opt 与 Lin–Kernighan 思想（简述）&quot;">​</a></h2><ul><li><strong>k-opt</strong>：同时删 k 条边并以某种方式重连；一般 k&gt;3 时穷举不可行。</li><li><strong>Lin–Kernighan（LK） 类算法</strong>：不固定大 k 穷举，而沿链式交换边（λ-opt 链、动态扩展）在多项式量时间内探索一大类高阶交换，是高质量 TSP 局搜的标杆之一；工程实现细节多，与单纯「枚举 k 条边」的课本定义有所区别。</li><li><strong>有向/非对称</strong>：边定向与重连规则要单独约定；许多仓库实现从对称 2-opt 起。</li></ul><p><strong>注</strong>：CVRP 等除长度外有容量、时间窗时，2-opt/3-opt 后须检查可行性，不可行则拒收该邻居。</p><hr><h2 id="主过程-2-opt-下降-最小化、示意框" tabindex="-1">主过程（2-opt 下降，最小化、示意框） <a class="header-anchor" href="#主过程-2-opt-下降-最小化、示意框" aria-label="Permalink to &quot;主过程（2-opt 下降，最小化、示意框）&quot;">​</a></h2><p>s 的存储方式（点序、前驱后继、边表）自洽即可；下框用「存在改进则更新」的写法。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 2-opt 局搜</p><h3 id="_1-输入" tabindex="-1">1. 输入 <a class="header-anchor" href="#_1-输入" aria-label="Permalink to &quot;1. 输入&quot;">​</a></h3><p>当前可行环（或路径，若你定义的是开路径 2-opt，规则相应调整）与距离。</p><h3 id="_2-邻域扫与改进" tabindex="-1">2. 邻域扫与改进 <a class="header-anchor" href="#_2-邻域扫与改进" aria-label="Permalink to &quot;2. 邻域扫与改进&quot;">​</a></h3><p>在 2-opt 邻域中若存在使总长更短的移动，任选一合法改进，更新 s，重复本步。<br> 可配合最陡/先改进与候选边表。</p><h3 id="_3-无改进" tabindex="-1">3. 无改进 <a class="header-anchor" href="#_3-无改进" aria-label="Permalink to &quot;3. 无改进&quot;">​</a></h3><p>若不存在改进的 2-opt，输出当前 s 作为 2-opt 局部最优（相对该邻域定义）。</p></div><p><strong>注</strong>：3-opt 主循环可仿上把「2-opt 邻域」换为「3-opt 重连的规范枚举」，因重连种数多，实现上多拆成子过程与剪枝，不必与本框一行一行等同。</p>',17)])])}const u=o(e,[["render",i]]);export{k as __pageData,u as default};
